module RefModule(
  input clock,
  input reset,
  input PCEn,
  input [7:0] in, 
  output [7:0] out
);reg [7:0] Data;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clock, posedge reset or posedge dbg_halt) begin

    if(reset)
      Data <= 8'b0;
    else if(PCEn)
      Data <= in;
  end
  assign out = Data;
endmodule
